SELECT DISTINCT a.name, a.version
FROM algorithms a
JOIN algorithm_results ar ON a.algorithm_id = ar.algorithm_id;

SELECT note, date
FROM project_notes
WHERE collaboration_id = 1 AND date >= '2023-05-02';

external_knowledge:
- 'typical run times' refer to the average execution times of the algorithms;
- 'how many parameters they usually take in and out' refers to the average number of input and output parameters;
- The count of parameters is derived based on the number of commas in the parameter strings plus one.

sql:
SELECT COUNT(*) as num_uses
FROM algorithm_results
WHERE dataset_id = 0;

SELECT name, description, size, source_url, license, file_format, num_samples, num_features
FROM dataset
WHERE name = 'Wine Quality Dataset';

SELECT DISTINCT u.username
FROM users u
JOIN project_notes pn ON u.user_id = pn.user_id;
